-- Predict26 WC2026 official FIFA squad data seed
-- Source: FIFA official SquadLists-English.pdf
-- Version: Monday, 8 June 2026 02:29 UTC | Version 1
-- This seed creates additive/staging tables only. Codex should adapt/import into final app tables after auditing live schema.

create table if not exists public.wc2026_squad_imports (
  id text primary key,
  competition_code text not null,
  source_name text not null,
  source_url text not null,
  source_version text not null,
  source_pdf_sha256 text not null,
  source_status text not null,
  generated_at timestamptz not null,
  validation_status text not null
);

create table if not exists public.wc2026_squad_players_seed (
  competition_code text not null,
  team_code text not null,
  team_name text not null,
  squad_number integer not null,
  position text not null,
  player_name text not null,
  first_names text,
  last_names text,
  name_on_shirt text,
  date_of_birth date,
  date_of_birth_raw text,
  club_name text,
  club_country_code text,
  club_raw text,
  height_cm integer,
  source_name text not null,
  source_url text not null,
  source_version text not null,
  source_pdf_page integer not null,
  source_status text not null,
  last_verified_at timestamptz not null,
  primary key (competition_code, team_code, squad_number)
);

on conflict (id) do update set validation_status = excluded.validation_status, generated_at = excluded.generated_at;

on conflict (competition_code, team_code, squad_number) do update set
  position = excluded.position,
  player_name = excluded.player_name,
  first_names = excluded.first_names,
  last_names = excluded.last_names,
  name_on_shirt = excluded.name_on_shirt,
  date_of_birth = excluded.date_of_birth,
  date_of_birth_raw = excluded.date_of_birth_raw,
  club_name = excluded.club_name,
  club_country_code = excluded.club_country_code,
  club_raw = excluded.club_raw,
  height_cm = excluded.height_cm,
  source_version = excluded.source_version,
  source_status = excluded.source_status,
  last_verified_at = excluded.last_verified_at;

